data.source_css:
.newsletter { padding: 5rem 0; }
.newsletter__inner { max-width: 560px; margin: 0 auto; text-align: center; }
.newsletter__inner h2 { font-size: 1.875rem; margin-bottom: 0.75rem; }
.newsletter__inner > p { opacity: 0.75; margin-bottom: 1.75rem; }
.newsletter__form { display: flex; gap: 0.5rem; flex-wrap: wrap; justify-content: center; }
.newsletter__input { flex: 1; min-width: 220px; padding: 0.65rem 1rem; border-radius: 6px; border: 1.5px solid var(--color-border, #e2e8f0); background: transparent; color: inherit; font-size: 1rem; outline: none; }
.newsletter__input:focus { border-color: var(--color-primary, #2563eb); }
.newsletter__note { font-size: 0.8rem; opacity: 0.5; margin-top: 1rem; }
